Cline 安装 Node.js 启动的 MCP Server 连接失败 问题描述 在 Windows 环境下，使用 npx 启动 MCP Server 时出现以下错误：
spawn npx ENOENT spawn npx ENOENT 解决方案 将启动方式从 npx 改为 node 启动。
具体步骤 安装依赖： npm install -g @modelcontextprotocol/server-filesystem 修改配置文件： &#34;filesystem&#34;: { &#34;command&#34;: &#34;node&#34;, &#34;args&#34;: [ &#34;C:/Users/xxx/AppData/Roaming/npm/node_modules/@modelcontextprotocol/server-filesystem/dist/index.js&#34;, &#34;e:/study/my_pages&#34; ], &#34;disabled&#34;: false, &#34;autoApprove&#34;: [], &#34;timeout&#34;: 30 } 修改前配置 &#34;filesystem&#34;: { &#34;command&#34;: &#34;npx&#34;, &#34;args&#34;: [ &#34;-y&#34;, &#34;@modelcontextprotocol/server-filesystem&#34;, &#34;e:/study/my_pages&#34; ], &#34;disabled&#34;: false, &#34;autoApprove&#34;: [], &#34;timeout&#34;: 30 }

Flask结合nacos和graphql构建微服务
准备 pip install nacos-sdk-python pip install graphene Flask结合graphql from graphene import ObjectType, Field, String,Int # 自定义的类型 class ItemList(ObjectType): class Meta: description = &#34;这是返回类型的注释，要放在Meta类中，graphql会显示&#34; data = List(Item) # list列表，Item是自定义类型 total = Int()	# 标量类型 page = Field(PageInfo)	# PageInfo是自定义类型，自定义类型需要有Field() class Query(ObjectType): hello = Field(Result, user_name=String()) # Result是返回结果，name是参数 itemList = Field(ItemList,a = Int(),b = Int()) # ItemList是返回类型，a和b是传入的参数 def resolve_hello(root, info,user_name): return Result(1,&#34;ok&#34;) def resolve_itemList(root,info,a,b): return ItemList() schema = Schema(query=Query) def create_app(): app = Flask(__name__) app.add_url_rule(&#39;/graphql&#39;, view_func=GraphQLView.as_view(&#39;graphql&#39;, schema=schema, graphiql=True)) @app.route(&#39;/hello&#39;, methods=[&#39;get&#39;]) def hello(): # 普通请求 return &#34;hello&#34; return app if __name__ == &#39;__main__&#39;: app = create_app() ip = getIp() print(ip) app.run(ip,9099,debug=True) # 用如下方式，如果不想出现WARNING: This is a development server. Do not use it in a production deployment. # server = pywsgi.WSGIServer((ip, 9099), app) # server.serve_forever() # 在ip:9099/graphql下，即可访问 # 在graphql中，请求如下 #{ #	hello(user_name:&#34;tom&#34;){ result } #} 注册服务&amp;维持心跳 import time import nacos import socket def getIp(): hostname = socket.gethostname() ip = socket.gethostbyname(hostname) return ip SERVER_ADDRESSES = &#34;1.1.1.1:8848&#34; NAMESPACE = &#34;public&#34; client = nacos.NacosClient(SERVER_ADDRESSES, namespace=NAMESPACE, username=&#34;nacos&#34;, password=&#34;nacos&#34;) # 注册实例 client.add_naming_instance(&#34;service-hello&#34;, ip=utils.getIp(), port=&#34;9099&#34;) # 需要不断发送心跳 while True: time.sleep(3) client.send_heartbeat(&#34;service-hello&#34;,ip=getIp(),port=&#34;9099&#34;) # 持续发心跳 spring调用python的微服务
// FeignClient接口 @Service @FeignClient(name = &#34;service-hello&#34;) public interface AnormalClient { @PostMapping(value=&#34;/graphql&#34;, consumes= MediaType.APPLICATION_JSON_VALUE) String graphql(String sql); @GetMapping(&#34;/hello&#34;) String hello(); } // 调用微服务 String name = &#34;tom&#34;; String q = String.format(&#34;{ hello(name: &#39;%s&#39;){code }}&#34;,name ).replace(&#39;\&#39;&#39;,&#39;&#34;&#39;); JSONObject jsonObject=new JSONObject(); jsonObject.put(&#34;query&#34;,q); System.out.println(jsonObject.toJSONString()); String result = anormalClient.graphql(jsonObject.toJSONString()); System.out.println(result); 遇到的问题 There was an unexpected error (type=Internal Server Error, status=500).message&#34;:&#34;Must provide query string.&#34;1 在postman上按照graphql的格式请求可以正常返回结果2 抓包后发现请求是 content-type:text/plain 格式的。3 在postman上按照 content-type:application/json格式请求时，可以正常返回结果。在postman上按照 content-type:text/plain 的格式请求，出现同样错误message&#34;:&#34;Must provide query string&#34;，所以错误原因时请求的content-type格式问题。4 将请求设置为appllication/json格式只需要修改注解即可：consumes指定content-Type格式。@PostMapping(value=&#34;hello&#34;,consumes= MediaType.APPLICATION_JSON_VALUE)测试通过。
